const entrada  = $('Set Entrada').item.json;
const sessRaw  = $('GET Sessao').item.json;
const histRaw  = $('GET Historico').item.json;
const erpRaw   = $('POST ERP Enrichment').item.json;
const sessao   = sessRaw.session ?? {};
const historico = histRaw.history ?? [];
const erp      = erpRaw.result ?? erpRaw;
const F        = erp.financial ?? {};
const msg      = (entrada.mensagem_efetiva || entrada.mensagem || '').toLowerCase().trim();
const msgOriginal = entrada.mensagem_efetiva || entrada.mensagem || '';

// ?? Detec??o de CPF na mensagem ??????????????????????????????
const cpfRegex = /(\d{3}\.?\d{3}\.?\d{3}-?\d{2}|\d{11})/;
const cpfEncontrado = msgOriginal.match(cpfRegex)?.[0]?.replace(/\D/g, '') ?? null;
const cpfSessao = sessao.dados_coletados?.cpf ?? sessao.cpf ?? null;
const cpfAtivo = cpfEncontrado ?? cpfSessao ?? null;

// ?? Detec??o de sele??o de contrato ??????????????????????????
const contratoSelecionado = sessao.contrato_id ?? null;
const multiplosContratos = erp.multiplos_contratos ?? false;
const aguardandoCpf = erp.aguardando_cpf ?? false;
const contratos = erp.contratos ?? [];

// ?? Nome do cliente ???????????????????????????????????????????
const clienteNome = erp.contrato_selecionado?.cliente?.name
  ?? erp.cliente?.name
  ?? sessao.cliente_nome
  ?? entrada.contact_name
  ?? 'Cliente';

const jaIdentificado = sessao.identificado === true || !!cpfAtivo;
const fluxoAtual     = sessao.fluxo_atual ?? 'menu';
const primeiraMensagem = historico.length === 0;

// ?? Hist?rico formatado ???????????????????????????????????????
const historicoFormatado = historico.length > 0
  ? historico.map(t => `${t.role==='user'?'Cliente':'Agente'}: ${t.content}`).join('\n')
  : 'Primeira intera??o.';

// ?? SDR: classifica??o de intent ??????????????????????????????
let intent = 'MENU';

const eSaudacao = ['oi','ol?','ola','bom dia','boa tarde','boa noite','hello','hi','hey','oii','oiii'].some(s=>msg===s||msg.startsWith(s+' '));

// Cliente enviou CPF ? intent especial para processar identifica??o
if (cpfEncontrado && !cpfSessao) {
  intent = 'IDENTIFICACAO';
}
// M?ltiplos contratos e cliente ainda n?o escolheu ? aguardar sele??o
else if (multiplosContratos && !contratoSelecionado) {
  intent = 'SELECAO_CONTRATO';
}
// Aguardando CPF ? solicitar identifica??o
else if (aguardandoCpf && !cpfAtivo) {
  intent = 'SOLICITAR_CPF';
}
// Est? em fluxo espec?fico e n?o mudou de assunto
else if (fluxoAtual !== 'menu' && !eSaudacao) {
  intent = fluxoAtual.toUpperCase();
}

// Keywords por departamento
const kSup  = ['suporte','sem internet','internet caiu','lento','lentid?o','offline','n?o conecta','sem sinal','reiniciar','roteador','velocidade','queda'];
const kFin  = ['financeiro','fatura','boleto','pagar','d?bito','cobran?a','segunda via','pix','vencimento','renegocia??o','desbloquear','promessa'];
const kCom  = ['contratar','novo plano','planos','upgrade','instala??o','mudar plano','comercial','assinar','pacote','velocidade maior'];
const kHum  = ['humano','atendente','pessoa','falar com','transferir','quero falar'];

if (intent === 'MENU' || intent === 'MENU') {
  if (kHum.some(w=>msg.includes(w)))       intent = 'HUMANO';
  else if (kSup.some(w=>msg.includes(w)))  intent = 'SUPORTE';
  else if (kFin.some(w=>msg.includes(w)))  intent = 'FINANCEIRO';
  else if (kCom.some(w=>msg.includes(w)))  intent = 'COMERCIAL';
  else if (eSaudacao || primeiraMensagem)   intent = 'MENU';
}

// Override: suspenso ? financeiro
if (F.is_suspended && intent === 'MENU') intent = 'FINANCEIRO';

return [{json:{
  ...erp,
  mensagem:              msg,
  mensagem_original:     msgOriginal,
  conversation_id:       entrada.conversation_id,
  workspace_id:          entrada.workspace_id,
  telefone:              entrada.telefone,
  contact_name:          entrada.contact_name,
  cliente_nome:          clienteNome,
  ja_identificado:       jaIdentificado,
  primeira_mensagem:     primeiraMensagem,
  fluxo_atual:           fluxoAtual,
  historico_formatado:   historicoFormatado,
  sessao,
  intent,
  cpf_ativo:             cpfAtivo,
  cpf_encontrado:        cpfEncontrado,
  multiplos_contratos:   multiplosContratos,
  contratos:             contratos,
  contrato_selecionado:  erp.contrato_selecionado ?? null,
  aguardando_cpf:        aguardandoCpf,
}}];

const ctx  = $('Code: Contexto + SDR').item.json;
const nome = ctx.cliente_nome ?? 'Cliente';
const isCliente = ctx.ja_identificado && !!ctx.cliente?.id;
let saudacao;
if (ctx.primeira_mensagem) {
  if (isCliente) {
    saudacao = `Olá, ${nome}! Que bom ter você aqui!\n\nVi que você já é nosso cliente. Como posso ajudar hoje?`;
  } else {
    saudacao = `Olá! Seja bem-vindo(a)!\n\nSou o assistente virtual. Como posso ajudar?`;
  }
} else {
  saudacao = `${nome}, como posso ajudar? Selecione uma opção abaixo:`;
}
const sections = [
  {
    title: "Atendimento",
    rows: [
      { id: "SUPORTE",    title: "Suporte Técnico",     description: "Internet lenta, sem conexão, problemas" },
      { id: "FINANCEIRO", title: "Financeiro",               description: "Faturas, pagamentos, desbloqueio" },
      { id: "COMERCIAL",  title: "Comercial",                description: "Novos planos, upgrade, contratação" },
      { id: "HUMANO",     title: "Falar com Atendente",      description: "Atendimento humano" },
    ]
  }
];
return [{json:{
  saudacao,
  sections,
  conversation_id: ctx.conversation_id,
  workspace_id:    ctx.workspace_id,
  cliente_nome:    nome,
  ja_identificado: isCliente,
  cliente_id:      ctx.cliente?.id ?? null,
}}];

const ctx  = $('Code: Contexto + SDR').item.json;
const hist = $('GET Historico').item.json.history ?? [];
const resumo = hist.slice(-6).map(t=>`${t.role==='user'?'Cliente':'Agente'}: ${t.content}`).join('
');
const msg = `?? *Transferindo para atendente humano*

${ctx.cliente_nome}, vou te conectar com um de nossos especialistas agora.

Aguarde um momento! ??`;
return [{json:{ mensagem_transferencia: msg, resumo_conversa: resumo, conversation_id: ctx.conversation_id, workspace_id: ctx.workspace_id }}];

const entrada   = $('Set Entrada').item.json;
const sessao    = $('GET Sessao').item.json.session ?? {};
const erp       = $('POST ERP Enrichment').item.json?.result ?? $('POST ERP Enrichment').item.json ?? {};
const sdr       = $json;

const fluxoAtual      = sessao.fluxo_atual ?? 'menu';
const novoIntent      = sdr.intent;
const primeiraMensagem = sdr.primeira_mensagem;
const clienteNome     = sdr.cliente_nome ?? '';
const primeiroNome    = clienteNome.split(' ')[0] || 'cliente';
const F               = erp.financial ?? erp.financeiro ?? {};

const intentToFluxo = { SUPORTE:'suporte', FINANCEIRO:'financeiro', COMERCIAL:'comercial', MENU:'menu', HUMANO:'humano' };
const novoFluxo     = intentToFluxo[novoIntent] ?? 'menu';
const mudouDeFluxo  = fluxoAtual !== novoFluxo && novoFluxo !== 'menu' && fluxoAtual !== 'menu';
const entrouEmFluxo = fluxoAtual === 'menu' && novoFluxo !== 'menu';

let mensagemTransicao = null;
let deveSendTransicao = false;
let briefing = '';

if (mudouDeFluxo || entrouEmFluxo) {
  deveSendTransicao = true;

  switch(novoIntent) {
    case 'SUPORTE': {
      const statusConexao = erp.conexao?.status ?? erp.connection?.status ?? 'desconhecido';
      const estaOffline   = erp.conexao?.esta_offline ?? erp.conexao?.offline ?? false;
      mensagemTransicao = `Entendido${primeiroNome ? ', ' + primeiroNome : ''}! Vou verificar a situacao da sua conexao agora.`;
      briefing = `BRIEFING DO ORQUESTRADOR: Cliente reportou problema de suporte. Status da conexao no ERP: ${statusConexao}. ${estaOffline ? 'ATENCAO: conexao offline no ERP.' : ''} Va direto ao diagnostico sem apresentacoes.`;
      break;
    }
    case 'FINANCEIRO': {
      const valor    = F.valor_devido ?? F.amount_due ?? 0;
      const suspenso = F.esta_suspenso ?? F.is_suspended ?? false;
      const faturas  = F.faturas_abertas ?? F.open_invoices ?? 0;
      mensagemTransicao = `Certo! Deixa eu verificar sua situacao financeira...`;
      briefing = `BRIEFING DO ORQUESTRADOR: Cliente quer tratar financeiro. Situacao: valor devido R$${valor}, ${faturas} fatura(s) em aberto, conexao ${suspenso ? 'SUSPENSA' : 'ativa'}. Apresente esses dados imediatamente na primeira resposta sem perguntar nada.`;
      break;
    }
    case 'COMERCIAL': {
      const plano      = erp.cliente?.plano ?? erp.client?.plan ?? 'nao identificado';
      const velocidade = erp.cliente?.velocidade ?? erp.client?.speed ?? '';
      mensagemTransicao = `Otimo! Vou te mostrar as opcoes disponiveis.`;
      briefing = `BRIEFING DO ORQUESTRADOR: Cliente interessado em planos/upgrade. Plano atual: ${plano}${velocidade ? ' / ' + velocidade : ''}. Ofereca opcoes relevantes para o perfil.`;
      break;
    }
  }
}

if (!deveSendTransicao && novoFluxo !== 'menu') {
  briefing = `Continuacao do atendimento em ${novoFluxo}. NAO se apresente. Continue exatamente de onde parou na conversa.`;
}

if (primeiraMensagem && novoFluxo === 'menu') {
  briefing = 'Primeira interacao do cliente. O menu sera enviado em seguida.';
}

return [{json: {
  ...sdr,
  intent: novoIntent,
  orquestrador: {
    deve_enviar_transicao: deveSendTransicao,
    mensagem_transicao: mensagemTransicao,
    briefing,
    fluxo_anterior: fluxoAtual,
    novo_fluxo: novoFluxo
  }
}}];

const entrada = $('Set Entrada').item.json;
const resultado = $json;
const status = resultado.status;
let mensagem = '';
switch(status) {
  case 'aguardando_cpf':
    mensagem = 'Olá! Para continuar, preciso confirmar sua identidade.\n\nPor favor, me informe seu *CPF* (somente números):';
    break;
  case 'nao_encontrado':
    mensagem = 'Não encontrei cadastro com esse CPF. Verifique os números e tente novamente, ou digite *humano* para falar com um atendente.';
    break;
  case 'multiplos_contratos':
    const lista = resultado.contratos.map((c, i) => `*${i+1}.* ${c.endereco ?? 'Endereço não informado'} - Plano: ${c.plano ?? '-'} (${c.status ?? '-'})`).join('\n');
    mensagem = `Encontrei *${resultado.contratos.length} contratos* vinculados ao seu CPF:\n\n${lista}\n\nQual contrato você quer tratar? Responda com o *número* da opção.`;
    break;
  case 'identificado':
    const nome = resultado.cliente?.name?.split(' ')[0] ?? 'cliente';
    mensagem = `Identidade confirmada! Olá, *${nome}*!\n\nComo posso te ajudar hoje?`;
    break;
  default:
    mensagem = 'Ocorreu um erro. Por favor, tente novamente.';
}
return [{json:{ workspace_id: entrada.workspace_id, conversation_id: entrada.conversation_id, mensagem, status }}];

